import React from 'react';
import { BrowserRouter as Router, Routes, Route } from 'react-router-dom';
import { AuthProvider } from './context/AuthContext';
import HomePage from './components/HomePage';
import CoursesPage from './components/CoursesPage';
import About from './components/About';
import KnowledgeBase from './components/KnowledgeBase';
import CommunityForum from './components/CommunityForum';
import UserDashboard from './components/user/UserDashboard';
import UserProfile from './components/user/UserProfile';
import UserCertificatesList from './components/user/UserCertificatesList';
import CertificateRequestForm from './components/user/CertificateRequestForm';
import AdminDashboard from './components/admin/AdminDashboard';
import UsersList from './components/admin/UsersList';
import CertificatesList from './components/admin/CertificatesList';
import Statistics from './components/admin/Statistics';
import CertificateWall from './components/CertificateWall';
import VerifyCertificate from './components/VerifyCertificate';
import Login from './components/auth/Login';
import Register from './components/auth/Register';
import Navigation from './components/Navigation';
import Contact from './components/Contact';
import NotFound from './components/NotFound';

function App() {
  return (
    <Router>
      <AuthProvider>
        <div className="min-h-screen flex flex-col">
          <Navigation />
          <div className="flex-grow">
            <Routes>
              <Route path="/login" element={<Login />} />
              <Route path="/register" element={<Register />} />
              <Route path="/dashboard" element={<UserDashboard />} />
              <Route path="/courses" element={<CoursesPage />} />
              <Route path="/about" element={<About />} />
              <Route path="/knowledge-base" element={<KnowledgeBase />} />
              <Route path="/community-forum" element={<CommunityForum />} />
              <Route path="/user-certificates" element={<UserCertificatesList />} />
              <Route path="/certificates/request" element={<CertificateRequestForm />} />
              <Route path="/profile" element={<UserProfile />} />
              <Route path="/admin" element={<AdminDashboard />} />
              <Route path="/admin/users" element={<UsersList />} />
              <Route path="/admin/certificates" element={<CertificatesList />} />
              <Route path="/admin/statistics" element={<Statistics />} />
              <Route path="/certificates" element={<CertificateWall />} />
              <Route path="/verify-certificate" element={<VerifyCertificate />} />
              <Route path="/contact" element={<Contact />} />
              <Route path="/" element={<HomePage />} />
              <Route path="*" element={<NotFound />} />
            </Routes>
          </div>
        </div>
      </AuthProvider>
    </Router>
  );
}

export default App;
